import { Component, OnInit } from '@angular/core';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';
import { Router } from '@angular/router';
import { AuthService } from '../../../../core/services/auth.service';
import { RegisterRequest } from '../../../../core/models/user.model';

@Component({
  selector: 'app-register',
  templateUrl: './register.component.html',
  styleUrls: ['./register.component.scss']
})
export class RegisterComponent implements OnInit {
  registerForm: FormGroup;
  isLoading = false;
  errorMessage = '';

  constructor(
    private fb: FormBuilder,
    private authService: AuthService,
    private router: Router
  ) {
    this.registerForm = this.fb.group({
      nome: ['', [Validators.required, Validators.minLength(2)]],
      cognome: ['', [Validators.required, Validators.minLength(2)]],
      email: ['', [Validators.required, Validators.email]],
      password: ['', [Validators.required, Validators.minLength(6)]],
      confirmPassword: ['', [Validators.required]]
    }, { validators: this.passwordMatchValidator });
  }

  ngOnInit(): void {}

  passwordMatchValidator(form: FormGroup): { [key: string]: boolean } | null {
    const password = form.get('password')?.value;
    const confirmPassword = form.get('confirmPassword')?.value;

    if (password && confirmPassword && password !== confirmPassword) {
      return { passwordMismatch: true };
    }
    return null;
  }

  onSubmit(): void {
    if (this.registerForm.invalid) {
      this.registerForm.markAllAsTouched();
      return;
    }

    this.isLoading = true;
    this.errorMessage = '';

    const { confirmPassword, ...registerData } = this.registerForm.value;
    const registrationData: RegisterRequest = registerData;

    this.authService.register(registrationData).subscribe({
      next: (response) => {
        // La registrazione ora restituisce token e dati utente
        if (response && response.token && response.user) {
          // Salva il token e i dati utente
          localStorage.setItem('token', response.token);
          this.authService.setCurrentUser(response.user);

          // Vai alla dashboard
          this.router.navigate(['/dashboard']);
        } else {
          // Fallback: prova login manuale
          this.authService.login({
            email: registrationData.email,
            password: registrationData.password
          }).subscribe({
            next: () => {
              this.router.navigate(['/dashboard']);
            },
            error: (error) => {
              this.errorMessage = 'Registration successful but login failed. Please try logging in manually.';
              this.isLoading = false;
            },
            complete: () => {
              this.isLoading = false;
            }
          });
        }
      },
      error: (error) => {
        this.errorMessage = error.error?.message || 'Registration failed. Please try again.';
        this.isLoading = false;
      }
    });
  }

  get nome() { return this.registerForm.get('nome'); }
  get cognome() { return this.registerForm.get('cognome'); }
  get email() { return this.registerForm.get('email'); }
  get password() { return this.registerForm.get('password'); }
  get confirmPassword() { return this.registerForm.get('confirmPassword'); }
}
<div class="auth-container">
  <div class="auth-card">
    <div class="auth-header">
      <h1 class="auth-title">Join HackHub</h1>
      <p class="auth-subtitle">Create your account and start hacking</p>
    </div>

    <form [formGroup]="registerForm" (ngSubmit)="onSubmit()" class="auth-form" autocomplete="on">
      <div class="form-row">
        <div class="form-group">
          <label for="nome" class="form-label">First Name</label>
          <input
            id="nome"
            type="text"
            formControlName="nome"
            class="form-control"
            placeholder="Enter your first name"
            autocomplete="given-name"
            [class.is-invalid]="nome?.invalid && nome?.touched"
          >
          <div class="invalid-feedback" *ngIf="nome?.invalid && nome?.touched">
            <span *ngIf="nome?.errors?.['required']">First name is required</span>
            <span *ngIf="nome?.errors?.['minlength']">First name must be at least 2 characters</span>
          </div>
        </div>

        <div class="form-group">
          <label for="cognome" class="form-label">Last Name</label>
          <input
            id="cognome"
            type="text"
            formControlName="cognome"
            class="form-control"
            placeholder="Enter your last name"
            autocomplete="family-name"
            [class.is-invalid]="cognome?.invalid && cognome?.touched"
          >
          <div class="invalid-feedback" *ngIf="cognome?.invalid && cognome?.touched">
            <span *ngIf="cognome?.errors?.['required']">Last name is required</span>
            <span *ngIf="cognome?.errors?.['minlength']">Last name must be at least 2 characters</span>
          </div>
        </div>
      </div>

      <div class="form-group">
        <label for="email" class="form-label">Email</label>
        <input
          id="email"
          type="email"
          formControlName="email"
          class="form-control"
          placeholder="Enter your email"
          autocomplete="email"
          [class.is-invalid]="email?.invalid && email?.touched"
        >
        <div class="invalid-feedback" *ngIf="email?.invalid && email?.touched">
          <span *ngIf="email?.errors?.['required']">Email is required</span>
          <span *ngIf="email?.errors?.['email']">Please enter a valid email</span>
        </div>
      </div>

      <div class="form-group">
        <label for="password" class="form-label">Password</label>
        <input
          id="password"
          type="password"
          formControlName="password"
          class="form-control"
          placeholder="Create a password"
          autocomplete="new-password"
          [class.is-invalid]="password?.invalid && password?.touched"
        >
        <div class="invalid-feedback" *ngIf="password?.invalid && password?.touched">
          <span *ngIf="password?.errors?.['required']">Password is required</span>
          <span *ngIf="password?.errors?.['minlength']">Password must be at least 6 characters</span>
        </div>
      </div>

      <div class="form-group">
        <label for="confirmPassword" class="form-label">Confirm Password</label>
        <input
          id="confirmPassword"
          type="password"
          formControlName="confirmPassword"
          class="form-control"
          placeholder="Confirm your password"
          autocomplete="new-password"
          [class.is-invalid]="confirmPassword?.invalid && confirmPassword?.touched"
        >
        <div class="invalid-feedback" *ngIf="confirmPassword?.invalid && confirmPassword?.touched">
          <span *ngIf="confirmPassword?.errors?.['required']">Please confirm your password</span>
          <span *ngIf="registerForm.errors?.['passwordMismatch']">Passwords do not match</span>
        </div>
      </div>

      <div class="alert alert-error" *ngIf="errorMessage">
        {{ errorMessage }}
      </div>

      <button type="submit" class="btn btn-primary btn-block" [disabled]="isLoading || registerForm.invalid">
        <span *ngIf="!isLoading">Create Account</span>
        <div class="spinner" *ngIf="isLoading"></div>
      </button>
    </form>

    <div class="auth-footer">
      <p>Already have an account? <a routerLink="/auth/login" class="auth-link">Sign in</a></p>
    </div>
  </div>
</div>
